package com.spendwise.prototype.ui; import android.os.Bundle; import androidx.appcompat.app.AppCompatActivity; import androidx.fragment.app.commit; import com.google.android.material.bottomnavigation.BottomNavigationView; import com.spendwise.prototype.R; class MainActivity:AppCompatActivity(){ override fun onCreate(b:Bundle?){ super.onCreate(b); setContentView(R.layout.activity_main); supportFragmentManager.commit{ replace(R.id.nav_host,AddExpenseFragment()) }; findViewById<BottomNavigationView>(R.id.bottom_nav).setOnItemSelectedListener{ val f=when(it.itemId){ R.id.nav_add->AddExpenseFragment(); R.id.nav_expenses->ExpensesListFragment(); else->GoalsFragment() }; supportFragmentManager.commit{ replace(R.id.nav_host,f) }; true } } }